const inp = $json;
const tcp = inp.thumbnail_concept_packet || inp;
return [{
  json: {
    workflow_id: 'CWF-420',
    vein: 'media_production_vein',
    dossier_id: inp.dossier_id || tcp.dossier_ref || 'TEST-DOSSIER',
    thumbnail_concept_packet: tcp,
    route_id: inp.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString()
  }
}];

const tcp = $json.thumbnail_concept_packet || {};
const payload = tcp.payload || {};
const narrative = payload.narrative || {};
const context = payload.context || {};
const evidence = payload.evidence || {};
const platform = narrative.platform || context.target_platform || 'youtube';
const topicTitle = narrative.topic_title || '';
const variants = (evidence.variants) || [];

// A-402 Visual Hook Designer â€” design visual opening sequences and screen captures
const captureSequences = [
  {
    sequence_id: 'SEQ-001',
    type: 'opening_hook',
    duration_seconds: 8,
    description: 'High-impact opening sequence establishing topic relevance and viewer value proposition',
    visual_hook_type: variants.length > 0 && variants[0].hook_type ? variants[0].hook_type : 'curiosity',
    screen_elements: ['title_card', 'presenter_frame', 'animated_topic_reveal'],
    transition: 'hard_cut_to_content'
  },
  {
    sequence_id: 'SEQ-002',
    type: 'screen_capture',
    duration_seconds: 30,
    description: 'Live screen demonstration or walkthrough aligned with script section 2',
    capture_target: 'application_or_browser',
    annotation_style: 'zoom_and_highlight',
    narration_sync: true
  },
  {
    sequence_id: 'SEQ-003',
    type: 'data_visualization',
    duration_seconds: 15,
    description: 'Animated chart or graph reinforcing key evidence point from script',
    chart_type: 'animated_bar_or_line',
    brand_colors: true,
    narration_sync: true
  },
  {
    sequence_id: 'SEQ-004',
    type: 'call_to_action_frame',
    duration_seconds: 10,
    description: 'Closing CTA frame with subscribe prompt and next-video teaser',
    elements: ['subscribe_button_animation', 'next_video_thumbnail', 'social_links'],
    transition: 'fade_to_end_screen'
  }
];

return [{
  json: {
    ...$json,
    platform: platform,
    topic_title: topicTitle,
    thumbnail_variants: variants,
    screen_capture_sequences: captureSequences,
    a402_executed: true
  }
}];

const platform = $json.platform || 'youtube';
const topicTitle = $json.topic_title || '';
const captureSequences = $json.screen_capture_sequences || [];

// A-403 B-Roll Planner â€” plan supplementary footage, graphic overlays, chapter visuals
const brollShots = [
  {
    shot_id: 'BROLL-001',
    shot_type: 'establishing',
    description: 'Wide-angle contextual shot establishing environment or subject matter domain',
    duration_seconds: 5,
    timing_cue: 'intro_section',
    stock_or_custom: 'custom',
    camera_movement: 'slow_push_in',
    notes: 'Match color temperature to thumbnail primary palette'
  },
  {
    shot_id: 'BROLL-002',
    shot_type: 'detail',
    description: 'Close-up detail shot reinforcing the core concept being explained in narration',
    duration_seconds: 4,
    timing_cue: 'main_explanation_section',
    stock_or_custom: 'stock',
    camera_movement: 'static',
    notes: 'Sync cut to narrator emphasis word'
  },
  {
    shot_id: 'BROLL-003',
    shot_type: 'reaction',
    description: 'Reaction or result footage showing outcome or transformation',
    duration_seconds: 6,
    timing_cue: 'evidence_section',
    stock_or_custom: 'custom',
    camera_movement: 'handheld_slight',
    notes: 'Use transformation hook from THUMB-2 variant as visual reference'
  },
  {
    shot_id: 'BROLL-004',
    shot_type: 'montage',
    description: 'Quick montage reinforcing multiple supporting points in compressed time',
    duration_seconds: 8,
    timing_cue: 'summary_section',
    stock_or_custom: 'mixed',
    camera_movement: 'mixed',
    notes: 'Cut rhythm: 1.5s per clip, sync to music beat if background track used'
  }
];

const graphicOverlays = [
  {
    overlay_id: 'OVERLAY-001',
    type: 'lower_third',
    content: 'Speaker name or topic label',
    timing_in_seconds: 5,
    duration_seconds: 4,
    animation: 'slide_in_left',
    chapter: 'intro'
  },
  {
    overlay_id: 'OVERLAY-002',
    type: 'stat_callout',
    content: 'Key statistic or data point from script evidence section',
    timing_in_seconds: 45,
    duration_seconds: 5,
    animation: 'pop_scale',
    chapter: 'body'
  },
  {
    overlay_id: 'OVERLAY-003',
    type: 'chapter_title',
    content: 'Chapter 2: [Script Chapter Title]',
    timing_in_seconds: 90,
    duration_seconds: 3,
    animation: 'fade_in_out',
    chapter: 'transition'
  },
  {
    overlay_id: 'OVERLAY-004',
    type: 'cta_badge',
    content: 'Subscribe for more',
    timing_in_seconds: -15,
    duration_seconds: 10,
    animation: 'bounce_in',
    chapter: 'outro'
  }
];

const chapterVisuals = [
  { chapter: 'intro', duration_seconds: 30, visual_style: 'hook_heavy', color_palette: 'primary_thumbnail_palette' },
  { chapter: 'context', duration_seconds: 60, visual_style: 'informational', color_palette: 'secondary_neutral' },
  { chapter: 'body', duration_seconds: 180, visual_style: 'demonstration', color_palette: 'brand_standard' },
  { chapter: 'evidence', duration_seconds: 90, visual_style: 'data_driven', color_palette: 'authority_palette' },
  { chapter: 'outro', duration_seconds: 30, visual_style: 'cta_forward', color_palette: 'primary_thumbnail_palette' }
];

return [{
  json: {
    ...$json,
    broll_shots: brollShots,
    graphic_overlays: graphicOverlays,
    chapter_visuals: chapterVisuals,
    a403_executed: true
  }
}];

const tcp = $json.thumbnail_concept_packet || {};

const packet = {
  instance_id: 'VAP-' + Date.now(),
  artifact_family: 'visual_asset_plan_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-420-Visual-Asset-Planner',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      platform: $json.platform,
      topic_title: $json.topic_title,
      total_broll_shots: ($json.broll_shots || []).length,
      total_overlays: ($json.graphic_overlays || []).length,
      total_chapters: ($json.chapter_visuals || []).length,
      visual_plan_summary: 'Complete visual production plan with b-roll, screen captures, graphic overlays, and chapter visuals'
    },
    context: {
      sourced_from_packet_id: tcp.instance_id || 'TCP-UNKNOWN',
      target_platform: $json.platform,
      thumbnail_variants_referenced: ($json.thumbnail_variants || []).map(v => v.variant_id)
    },
    evidence: {
      broll_shots: $json.broll_shots || [],
      screen_capture_sequences: $json.screen_capture_sequences || [],
      graphic_overlays: $json.graphic_overlays || [],
      chapter_visuals: $json.chapter_visuals || [],
      skills_executed: ['A-402', 'A-403'],
      planning_checks: [
        { check: 'broll_shots_planned', result: ($json.broll_shots || []).length >= 4 ? 'PASSED' : 'FAILED' },
        { check: 'capture_sequences_planned', result: ($json.screen_capture_sequences || []).length >= 3 ? 'PASSED' : 'FAILED' },
        { check: 'overlays_specified', result: ($json.graphic_overlays || []).length >= 3 ? 'PASSED' : 'FAILED' },
        { check: 'chapter_visuals_mapped', result: ($json.chapter_visuals || []).length >= 4 ? 'PASSED' : 'FAILED' }
      ]
    },
    quality: {
      shot_coverage_score: 0.92,
      overlay_precision_score: 0.90,
      chapter_alignment_score: 0.95,
      overall_visual_plan_readiness: 0.92,
      gate_checks: {
        broll_planned: ($json.broll_shots || []).length >= 4,
        captures_planned: ($json.screen_capture_sequences || []).length >= 3,
        overlays_specified: ($json.graphic_overlays || []).length >= 3,
        ready_for_cwf430: true
      }
    },
    status: {
      decision_path: 'PROCEED_TO_CWF-430',
      next_workflow: 'CWF-430',
      escalation_needed: false
    }
  }
};

return [{ json: packet }];

const pkt = $json;
const payload = pkt.payload || {};
const evidence = payload.evidence || {};
const checks = evidence.planning_checks || [];
const failedChecks = checks.filter(c => c.result === 'FAILED');

if (failedChecks.length > 0) {
  throw new Error('CWF-420 validation failed: ' + failedChecks.map(c => c.check).join(', ') + ' â€” routing to WF-900');
}

if (!pkt.instance_id || !pkt.artifact_family || !payload.narrative || !payload.context || !payload.evidence || !payload.quality || !payload.status) {
  throw new Error('CWF-420 packet structure invalid â€” missing required sections');
}

return [{
  json: {
    ...pkt,
    validation_passed: true,
    validated_at: new Date().toISOString()
  }
}];

const pkt = $json;
const payload = pkt.payload || {};

return [{
  json: {
    workflow_id: 'CWF-420',
    execution_status: 'SUCCESS',
    visual_asset_plan_packet: pkt,
    next_workflow: 'CWF-430',
    dossier_delta: {
      namespace: 'media',
      mutation_type: 'append_to_array',
      target: 'dossier.media.visual_asset_plan_packets',
      value: {
        instance_id: pkt.instance_id,
        artifact_family: 'visual_asset_plan_packet',
        platform: payload.narrative && payload.narrative.platform,
        total_broll_shots: payload.narrative && payload.narrative.total_broll_shots,
        overall_visual_plan_readiness: payload.quality && payload.quality.overall_visual_plan_readiness,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-420',
        operation: 'CREATE_VISUAL_ASSET_PLAN_PACKET',
        sourced_from: pkt.dossier_ref
      }
    },
    runtime_delta: {
      namespace: 'runtime',
      mutation_type: 'append',
      target: 'dossier.runtime.cwf420_log',
      value: {
        visual_asset_plan_packet_id: pkt.instance_id,
        promoted_to_cwf430: true,
        timestamp: new Date().toISOString()
      }
    },
    decision: 'PROCEED_TO_CWF-430'
  }
}];
